questions.answer:
Use a lock-free MPMC ring with per-slot sequence counters and atomic head/tail indices in a page-aligned shared memory region. Each slot is cache-line padded (~64 bytes) and contains a sequence number initialized to its slot index. Enqueue: (1) load head atomically, (2) compute slot = head & mask, (3) check if slot.seq == slot_index (slot is ready), (4) CAS head to head+1 to reserve (succeeds only if still valid), (5) write data, (6) update slot.seq = head + capacity with memory_order_release. Dequeue: symmetric - load tail, check slot.seq == tail + capacity (data ready), CAS tail to tail+1, read data, set slot.seq = slot_index with release for reuse. Power-of-two capacity enables wraparound via bitmask (index = pos & mask). Per-slot sequences increment monotonically, solving ABA by detecting when a slot has been recycled.

**C-like Implementation Sketch:**

```c
#define CACHE_LINE 64
#define SLOT_SIZE 128
#define CAPACITY 256  // power of two
#define MASK (CAPACITY - 1)

typedef struct {
    char data[SLOT_SIZE - sizeof(uint64_t)];
    _Atomic uint64_t seq;  // version counter for ABA prevention
} slot_t;

typedef struct {
    _Atomic uint64_t head;  // producer cursor
    _Atomic uint64_t tail;  // consumer cursor
    char pad[CACHE_LINE - sizeof(_Atomic uint64_t) * 2];
    slot_t slots[CAPACITY];
} ring_buffer_t;

// Page-aligned allocation for IPC
ring_buffer_t* create_shared_ring(void) {
    ring_buffer_t* rb = mmap(NULL, sizeof(ring_buffer_t),
                             PROT_READ|PROT_WRITE, MAP_SHARED|MAP_ANONYMOUS, -1, 0);
    madvise(rb, sizeof(ring_buffer_t), MADV_HUGEPAGE);  // optional huge pages
    rb->head = rb->tail = 0;
    for (int i = 0; i < CAPACITY; i++) {
        rb->slots[i].seq = i;  // initial sequence = slot index
    }
    return rb;
}

// Lock-free enqueue (for one producer thread)
bool enqueue(ring_buffer_t* rb, const void* data) {
    uint64_t head = atomic_load_explicit(&rb->head, memory_order_acquire);

    while (1) {
        uint64_t idx = head & MASK;
        slot_t* slot = &rb->slots[idx];
        uint64_t seq = atomic_load_explicit(&slot->seq, memory_order_acquire);

        // ABA check: slot ready only if seq matches our expected value
        if (seq != idx) {
            // Slot not ready, retry
            cpu_pause();
            head = atomic_load_explicit(&rb->head, memory_order_acquire);
            continue;
        }

        // CAS to reserve slot (advance head)
        uint64_t new_head = head + 1;
        if (atomic_compare_exchange_weak_explicit(&rb->head, &head, new_head,
                                                  memory_order_acq_rel,
                                                  memory_order_acquire)) {
            // Reserved: write data and publish with release barrier
            memcpy(slot->data, data, SLOT_SIZE - sizeof(uint64_t));
            atomic_store_explicit(&slot->seq, head + CAPACITY, memory_order_release);
            return true;
        }
        // CAS failed: another producer grabbed it, retry with updated head
    }
}

// Lock-free dequeue (for one consumer thread)
bool dequeue(ring_buffer_t* rb, void* data) {
    uint64_t tail = atomic_load_explicit(&rb->tail, memory_order_acquire);

    while (1) {
        uint64_t idx = tail & MASK;
        slot_t* slot = &rb->slots[idx];
        uint64_t seq = atomic_load_explicit(&slot->seq, memory_order_acquire);

        // Data ready only if seq == tail + CAPACITY (written by producer)
        uint64_t expected_seq = tail + CAPACITY;
        if (seq != expected_seq) {
            cpu_pause();
            tail = atomic_load_explicit(&rb->tail, memory_order_acquire);
            continue;
        }

        // CAS to reserve slot (advance tail)
        uint64_t new_tail = tail + 1;
        if (atomic_compare_exchange_weak_explicit(&rb->tail, &tail, new_tail,
                                                  memory_order_acq_rel,
                                                  memory_order_acquire)) {
            // Reserved: read data and recycle slot with release barrier
            memcpy(data, slot->data, SLOT_SIZE - sizeof(uint64_t));
            atomic_store_explicit(&slot->seq, idx, memory_order_release);
            return true;
        }
    }
}
```

**Wraparound Handling:** Since capacity is a power of two (e.g., 256), wraparound is handled via bitmask: `index = position & (CAPACITY-1)`. The 64-bit sequence counters never wrap in practice (2^64 operations), ensuring ABA safety even after many wraparounds.

**ABA Avoidance:** Each slot has a per-slot sequence number (version counter). Initially set to its slot index (0,1,2...). After a producer writes data, it increments to `head + CAPACITY`. After a consumer reads and recycles, it resets to the slot index. A CAS succeeds only if the sequence matches the expected value—if another producer consumed and recycled the slot in the meantime, the sequence would have changed, causing CAS to fail.

Design a NUMA-aware memory allocator extension for a 4-socket server running latency-sensitive trading workloads alongside background analytics. The allocator should prefer local memory pages, track per-node pressure metrics, and migrate thread affinity when cross-node access latency exceeds a configurable threshold.

**Core Data Structures:**

```c
typedef struct {
    int owner_node;
    int next_free;
    atomic_uint ref_count;
    uint64_t last_access_time;
} page_meta_t;

typedef struct {
    page_meta_t *pages;
    int free_list_head;
    atomic_uint free_count;
    atomic_uint pressure_metric;
    uint64_t remote_access_latency_ns;
} node_pool_t;

typedef struct {
    int current_node;
    uint64_t migration_threshold_ns;
    atomic_uint remote_miss_count;
    atomic_uint local_hit_count;
} thread_affinity_t;
```

**Key Functions:**

```c
page_meta_t *numa_alloc(int preferred_node) {
    // Try local pool first
    node_pool_t *pool = &global_pools[preferred_node];
    if (atomic_load(&pool->free_count) > 0) {
        return alloc_from_pool(pool);
    }
    // Fall back to least pressured remote node
    return alloc_from_remote_pool();
}

void migrate_thread_if_needed(thread_affinity_t *aff) {
    uint64_t avg_remote_latency = measure_remote_latency(aff->current_node);
    if (avg_remote_latency > aff->migration_threshold_ns) {
        int best_node = find_optimal_node();
        if (best_node != aff->current_node) {
            migrate_thread_to_node(aff, best_node);
        }
    }
}

void numa_free(page_meta_t *page) {
    node_pool_t *pool = &global_pools[page->owner_node];
    return_to_pool(pool, page);
}
```

**Test Plan:**
1. Simulate mixed workload with 2 trading threads (latency-sensitive) and 2 analytics threads (throughput-focused)
2. Measure remote memory access patterns before/after optimization using perf counters
3. Validate migration triggers at threshold: monitor migration frequency vs latency reduction
4. Benchmark scenarios: uniform access, hot-spot access, and bursty analytics loads
5. Collect metrics: remote miss rate (%), average access latency, migration overhead (% CPU time)

