## Code Example

```c
// Minimal sketch of a per-CPU sleep queue
typedef struct SleepEntry {
  uint64_t wake_at;
  int tid;
  struct SleepEntry *next;
} SleepEntry;

// Enqueue thread for timed sleep
void sleep(int tid, uint64_t duration) {
  uint64_t now = get_time();
  SleepEntry entry = {now + duration, tid};
  minheap_insert(&cpu->sleep_queue, entry);
  block_thread(tid);
}

// Timer interrupt handler
void timer_interrupt() {
  uint64_t now = get_time();
  while (!minheap_empty(&cpu->sleep_queue)) {
    SleepEntry entry = minheap_peek(&cpu->sleep_queue);
    if (entry.wake_at > now) break;

    entry = minheap_pop(&cpu->sleep_queue);
    if (entry.wake_at <= now) {
      wake_thread(entry.tid);
    } else {
      minheap_insert(&cpu->sleep_queue, entry);
    }
  }
}
```

