// Pseudocode: bounded mailbox in a tiny OS
class Mailbox {
  constructor(cap) {
    this.buf = new Array(cap);
    this.head = 0; this.tail = 0; this.count = 0; this.cap = cap;
    this.lock = new Mutex();
    this.notEmpty = new CondVar();
    this.notFull = new CondVar();
  }
}

function trySend(mb, m) {
  mb.lock.lock();
  if (mb.count === mb.cap) { mb.lock.unlock(); return false; }
  mb.buf[mb.tail] = m;
  mb.tail = (mb.tail + 1) % mb.cap;
  mb.count++;
  mb.notEmpty.signal();
  mb.lock.unlock();
  return true;
}

function blockingRecv(mb, out) {
  mb.lock.lock();
  while (mb.count === 0) {
    mb.notEmpty.wait(mb.lock);
  }
  *out = mb.buf[mb.head];
  mb.head = (mb.head + 1) % mb.cap;
  mb.count--;
  mb.notFull.signal();
  mb.lock.unlock();
}
```

