```c
// Pseudo-structs illustrating the approach
typedef struct Timer { 
    uint64_t expires; 
    void (*cb)(void*); 
    void *arg; 
    struct Timer *next; 
} Timer;

typedef struct TimerWheel {
    Timer *buckets[WHEEL_SIZE];
    uint64_t current_tick;
    atomic_int pending_count;
} TimerWheel;

// Global coarse wheel for far expirations
TimerWheel global_wheel;

// Per-core micro-wheels for hot timers
TimerWheel per_core_wheels[MAX_CPUS];

// Lock-free enqueue using atomic operations
void enqueue_timer(Timer *timer, int core_id) {
    uint64_t expires = timer->expires;
    TimerWheel *wheel;

    if (expires - current_time > COARSE_THRESHOLD) {
        wheel = &global_wheel;
    } else {
        wheel = &per_core_wheels[core_id];
    }

    uint64_t bucket_idx = expires % WHEEL_SIZE;

    // Atomic insertion into bucket
    do {
        timer->next = wheel->buckets[bucket_idx];
    } while (!atomic_compare_exchange_weak(
        &wheel->buckets[bucket_idx], 
        &timer->next, 
        timer
    ));

    atomic_fetch_add(&wheel->pending_count, 1);
}

// Tick advancement with cascading
void advance_tick(uint64_t new_tick) {
    // Advance global wheel first
    process_wheel_expirations(&global_wheel, new_tick);

    // Cascade to per-core wheels
    for (int i = 0; i < MAX_CPUS; i++) {
        process_wheel_expirations(&per_core_wheels[i], new_tick);
    }
}

// Timer coalescing during expiration
void process_wheel_expirations(TimerWheel *wheel, uint64_t tick) {
    uint64_t bucket_idx = tick % WHEEL_SIZE;
    Timer *timer = wheel->buckets[bucket_idx];
    Timer *coalesced_group = NULL;

    // Group timers with similar expirations
    while (timer) {
        Timer *next = timer->next;
        if (timer->expires <= tick) {
            // Add to coalesced group
            timer->next = coalesced_group;
            coalesced_group = timer;
        }
        timer = next;
    }

    // Execute coalesced group in single wakeup
    if (coalesced_group) {
        execute_coalesced_timers(coalesced_group);
        wheel->buckets[bucket_idx] = NULL;
        atomic_fetch_sub(&wheel->pending_count, 
                         count_timers(coalesced_group));
    }
}
```

