typedef struct ring { _Atomic(int) head, tail; req_t* buf[N]; } ring_t;
int enqueue(ring_t* r, req_t* e){
  int t = atomic_load(&r->tail);
  int next = (t + 1) % N;
  if (next == atomic_load(&r->head)) return -1; // full
  r->buf[t] = e;
  atomic_store(&r->tail, next);
  return 0;
}
req_t* dequeue(ring_t* r){
  int h = atomic_load(&r->head);
  int t = atomic_load(&r->tail);
  if (h == t) return NULL; // empty
  req_t* e = r->buf[h];
  atomic_store(&r->head, (h + 1) % N);
  return e;
}
