## Code Example
```c
// sketch
typedef struct {
  _Atomic int head;
  _Atomic int tail;
  void *buf[DEQUE_SIZE];
} Deque;

static inline void push(Deque *d, void *task) {
  int t = atomic_fetch_add_explicit(&d->tail, 1, memory_order_relaxed);
  d->buf[t & (DEQUE_SIZE-1)] = task;
}

static inline void *pop(Deque *d) {
  int t = atomic_fetch_sub_explicit(&d->tail, 1, memory_order_acq_rel);
  int h = atomic_load_explicit(&d->head, memory_order_acquire);
  if (t <= h) return NULL;
  return d->buf[(t-1) & (DEQUE_SIZE-1)];
}

static inline int steal(Deque *d, void **out) {
  int h = atomic_load_explicit(&d->head, memory_order_acquire);
  int t = atomic_load_explicit(&d->tail, memory_order_acquire);
  if (h >= t) return 0;
  void *candidate = d->buf[h & (DEQUE_SIZE-1)];
  if (atomic_compare_exchange_weak_explicit(&d->head, &h, h+1, memory_order_acq_rel, memory_order_acquire)) {
    *out = candidate;
    return 1;
  }
  return 0;
}
```

