## Code Example

```c
// Minimal skeleton
typedef struct { void *stack; void *guard; } Thread;

void thread_init(Thread *t) {
  t->stack = mmap(NULL, 8*1024*1024, PROT_READ|PROT_WRITE,
                  MAP_PRIVATE|MAP_ANONYMOUS, -1, 0);
  t->guard = (char*)t->stack - PAGE_SIZE;
  mprotect(t->guard, PAGE_SIZE, PROT_NONE);
}

void fault_handler(void *addr, Thread *t) {
  if (addr >= t->guard && addr < (char*)t->guard + PAGE_SIZE) {
    terminate_thread(t);
  }
}
``` 

