typedef struct Thread { int id; struct Thread *next; } Thread;

#define WHEEL_SIZE 64
typedef struct {
  Thread *buckets[WHEEL_SIZE];
  int current_tick;
  SpinLock lock;
} TimerWheel;

void sleep_ms(Thread *t, int ms, TimerWheel *w) {
  int slot = (w->current_tick + ms) % WHEEL_SIZE;
  spin_lock(&w->lock);
  t->next = w->buckets[slot];
  w->buckets[slot] = t;
  spin_unlock(&w->lock);
}

void timer_tick(TimerWheel *w) {
  spin_lock(&w->lock);
  int slot = w->current_tick % WHEEL_SIZE;
  Thread *cur = w->buckets[slot];
  w->buckets[slot] = NULL;
  w->current_tick++;
  spin_unlock(&w->lock);
  while (cur) { wake(cur); cur = cur->next; }
}
