bool enqueue(ring_t *r, int val){
  uint32_t t = atomic_fetch_add_explicit(&r->tail, 1, memory_order_relaxed);
  uint32_t h = atomic_load_explicit(&r->head, memory_order_acquire);
  if (t - h >= 256) return false; // full
  r->slots[t & 255] = val;
  atomic_thread_fence(memory_order_release);
  return true;
