// Minimal MVCC implementation for acquire/read/commit paths

typedef struct {
    uint64_t version;
    void*    data;
} Object;

// Acquire: snapshot version for consistent read
uint64_t acquire(Object* obj) {
    return obj->version;
}

// Read: fetch data, revalidate version
void* read(Object* obj, uint64_t snap) {
    void* val = obj->data;
    if (__sync_val_compare_and_swap(&obj->version, snap, snap) != snap) {
        return read(obj, acquire(obj)); // retry on concurrent write
    }
    return val;
}

// Commit: atomic swap with incremented version
int commit(Object* obj, void* new_data) {
    Object* new_obj = allocate_staging();
    new_obj->data = new_data;
    new_obj->version = obj->version + 1;
    return __sync_bool_compare_and_swap(&obj, obj, new_obj);
}
```

Under high contention, the retry loop in `read()` converges quickly as CAS failures indicate write-in-flight, and the coarse-grained lock per shard limits serialization to critical sections only, preserving throughput across cores.

