#define SIZE 1024  // power of two
#define MASK (SIZE - 1)

_Atomic size_t head = 0;
_Atomic size_t tail = 0;
type_t buffer[SIZE];

void enqueue(type_t value) {
    size_t h = atomic_fetch_add(&head, 1, memory_order_relaxed);
    buffer[h & MASK] = value;
    atomic_thread_fence(memory_order_release);
}

type_t dequeue(void) {
