typedef struct { _Atomic int state; /* 0/1/2 */ } page_t;

void access_page(page_t *p, void *dst) {
  int s = atomic_load_explicit(&p->state, memory_order_acquire);
  if (s == READY) { /* copy data to dst from page */ return; }
  if (s == UNLOADED) {
    if (atomic_compare_exchange_strong(&p->state, &UNLOADED, LOADING)) {
      // fault will be resolved by loader
      trigger_fault_and_load(p);
      atomic_store_explicit(&p->state, READY, memory_order_release);
      wake_waiters(p);
      /* copy data to dst */
      return;
    }
  }
  // wait until READY
  wait_on_futex(&p->state, READY);
  /* copy data */
}
