// Pseudo kernel path sketch (simplified)
ssize_t pipe_read(struct file *f, void __user *buf, size_t count) {
  struct pipe_inode_info *pipe = f->private_data;

  if (pipe_len(pipe) == 0) {
    if (f->f_flags & O_NONBLOCK)
      return -EAGAIN;

    // Block current task on pipe's wait queue
    wait_event_interruptible(pipe->wait, 
                            pipe_len(pipe) > 0 || pipe->writers == 0);
  }

  if (pipe_len(pipe) == 0 && pipe->writers == 0)
    return 0; // EOF

  // Copy data to user space
  ret = copy_to_user(buf, pipe->buf + pipe->cur, count);
  pipe->cur += count;
  pipe->len -= count;

  // Wake up writers if space available
  if (pipe->len < PIPE_BUF)
    wake_up_interruptible(&pipe->wait);

  return count;
}

ssize_t pipe_write(struct file *f, const void __user *buf, size_t count) {
  struct pipe_inode_info *pipe = f->private_data;

  // Wait for space if pipe is full
  wait_event_interruptible(pipe->wait,
                          pipe_len(pipe) < PIPE_BUF || pipe->readers == 0);

  // Copy from user to kernel pipe buffer
  copy_from_user(pipe->buf + pipe->len, buf, count);
  pipe->len += count;

  // Wake up blocked readers
  wake_up_interruptible(&pipe->wait);

  return count;
}
```

