pthread_mutex_t sqe_mutex = PTHREAD_MUTEX_INITIALIZER;

// Atomic SQE reservation with sequence numbers
static atomic_uint_fast64_t seq_counter = ATOMIC_VAR_INIT(0);

int submit_io_safe(int fd, void *buf, size_t len, uint64_t *seq_out) {
    // Reserve SQE atomically
    pthread_mutex_lock(&sqe_mutex);
    struct io_uring_sqe *sqe = io_uring_get_sqe(&ring);
    if (!sqe) {
        pthread_mutex_unlock(&sqe_mutex);
        return -EBUSY;
    }

    // Assign sequence number for ordering
    uint64_t seq = atomic_fetch_add_explicit(&seq_counter, 1, 
                                            memory_order_relaxed);
    *seq_out = seq;

    // Prepare submission with sequence tag
    io_uring_prep_write(sqe, fd, buf, len, 0);
    sqe->user_data = seq;

    // Release barrier before submit
    atomic_thread_fence(memory_order_release);
    int ret = io_uring_submit(&ring);
    pthread_mutex_unlock(&sqe_mutex);

    return ret;
}

// Completion processing with ordering
void process_completions(void) {
    struct io_uring_cqe *cqe;

    while (io_uring_peek_cqe(&ring, &cqe) == 0) {
        // Acquire barrier before reading completion
        atomic_thread_fence(memory_order_acquire);

        uint64_t seq = cqe->user_data;
        // Process completion in sequence order...

        io_uring_cqe_seen(&ring, cqe);
    }
}
```

