void enqueue_bottom(Deque* d, void* v){
  size_t t = atomic_load_explicit(&d->tail, memory_order_relaxed);
  d->slots[t & MASK] = v;
  atomic_store_explicit(&d->tail, t+1, memory_order_release);
}

void* dequeue_bottom(Deque* d){
  size_t t = atomic_load_explicit(&d->tail, memory_order_relaxed);
  if (t == atomic_load_explicit(&d->head, memory_order_acquire)) return NULL;
  void* v = d->slots[(t-1) & MASK];
  atomic_store_explicit(&d->tail, t-1, memory_order_relaxed);
  return v;
}

void* steal_top(Deque* d){
  size_t h = atomic_load_explicit(&d->head, memory_order_acquire);
  size_t t = atomic_load_explicit(&d->tail, memory_order_acquire);
  if (t <= h) return NULL;
  void* v = d->slots[h & MASK];
  if (atomic_compare_exchange_weak_explicit(&d->head, &h, h+1, memory_order_acquire, memory_order_relaxed))
    return v;
  return NULL;
}
