## Code Example

```c
typedef struct {
  void *data;
  atomic_int state; // 0=EMPTY,1=PENDING,2=LOADED,3=ERROR
  int waiters;
  pthread_mutex_t mutex;
  pthread_cond_t cond;
} cache_entry;

#define EMPTY 0
#define PENDING 1
#define LOADED 2
#define ERROR 3

void* block_read(int block_id) {
  cache_entry *entry = &cache[block_id];

  // Fast path
  if (atomic_load(&entry->state) == LOADED) {
    return entry->data;
  }

  pthread_mutex_lock(&entry->mutex);

  // Double-check after acquiring lock
  if (atomic_load(&entry->state) == LOADED) {
    pthread_mutex_unlock(&entry->mutex);
    return entry->data;
  }

  // Transition to PENDING if first thread
  if (atomic_compare_exchange_strong(&entry->state, &EMPTY, PENDING)) {
    enqueue_io_request(block_id);
  }

  // Block until I/O completes
  while (atomic_load(&entry->state) == PENDING) {
    entry->waiters++;
    pthread_cond_wait(&entry->cond, &entry->mutex);
    entry->waiters--;
  }

  pthread_mutex_unlock(&entry->mutex);

  if (atomic_load(&entry->state) == ERROR) {
    return NULL; // Propagate error
  }

  return entry->data;
}
```

