  for (uint32_t i = 1; i < 65536; i++) {
    if (!table[i].in_use) {
      table[i].in_use = true;
      table[i].gen++;
      int pid = (table[i].gen << 16) | i;
      pthread_mutex_unlock(&pid_lock);
