typedef struct { atomic_uint head, tail; Message buf[N]; } Channel;

bool send(Channel *c, Message m){
  unsigned long t = atomic_load_explicit(&c->tail, memory_order_relaxed);
  unsigned long w = (t + 1) % N;
  if (w == atomic_load_explicit(&c->head, memory_order_acquire)) return false; // full
  while (!atomic_compare_exchange_weak(&c->tail, &t, w, memory_order_acq_rel, memory_order_relaxed));
  c->buf[t] = m;
  atomic_thread_fence(memory_order_release);
  return true;
}

bool recv(Channel *c, Message *out){
  unsigned long h;
  do {
    h = atomic_load_explicit(&c->head, memory_order_relaxed);
    if (h == atomic_load_explicit(&c->tail, memory_order_acquire)) return false; // empty
  } while (!atomic_compare_exchange_weak(&c->head, &h, (h+1)%N, memory_order_acq_rel, memory_order_relaxed));
  *out = c->buf[h];
  return true;
}
```

