typedef struct Timer {
  uint64_t expiry; // system ticks
  struct Task* t;
  struct Timer* next;
} Timer;

#define WHEEL_SIZE 256

typedef struct TimerWheel {
  Timer* buckets[WHEEL_SIZE];
  uint64_t current;
  spinlock_t lock;
} TimerWheel;

void insert_timer(TimerWheel* w, Timer* tm, uint64_t expiry) {
  uint64_t now = get_current_tick();
  uint64_t delta = (expiry > now) ? (expiry - now) : 0;
  uint64_t idx = (w->current + (delta % WHEEL_SIZE)) % WHEEL_SIZE;
  tm->expiry = expiry;
  tm->next = w->buckets[idx];
  w->buckets[idx] = tm;
}
