#define N 10

int buffer[N];
int in = 0, out = 0;
sem_t empty, full;
pthread_mutex_t mutex;

void produce(int item) {
  sem_wait(&empty);
  pthread_mutex_lock(&mutex);
  buffer[in] = item;
  in = (in + 1) % N;
  pthread_mutex_unlock(&mutex);
  sem_post(&full);
}

int consume() {
  int item;
  sem_wait(&full);
  pthread_mutex_lock(&mutex);
  item = buffer[out];
  out = (out + 1) % N;
  pthread_mutex_unlock(&mutex);
  sem_post(&empty);
  return item;
}
```

